const url = $json.body.url || '';
if (!url) return [{ json: { productContext: 'No URL provided', product: {} } }];

const origUrl = url.startsWith('http') ? url : 'https://' + url;
let productCtx = '';
let productData = {};

try {

  // ── MakerWorld: use official API ─────────────────────────────────
  if (origUrl.includes('makerworld.com')) {
    const idMatch = origUrl.match(/\/models\/(\d+)/);
    if (idMatch) {
      const resp = await $helpers.httpRequest({
        method: 'GET',
        url: 'https://makerworld.com/api/v1/design-service/design/detail?designId=' + idMatch[1],
        headers: { 'Accept': 'application/json' }
      });
      const m = resp.data || resp || {};
      const stats = m.summary || m.stat || {};
      const creator = m.user || m.designer || {};
      productData = {
        title: m.name || m.title || null,
        description: String(m.description || '').substring(0, 200),
        author: creator.name || creator.handle || creator.username || null,
        likes: stats.likeCount || stats.like || null,
        downloads: stats.downloadCount || stats.download || null,
        makes: stats.makeCount || stats.make || null,
        image: m.coverMedia ? 'https://makerworld.bblmake.com/' + m.coverMedia.filePath : null,
        sourceHost: 'makerworld.com'
      };
      productCtx = 'SOURCE URL: ' + origUrl + '\n\nSTRUCTURED DATA FROM MAKERWORLD API:\n' + JSON.stringify({
        title: productData.title,
        description: String(m.description || '').substring(0, 400),
        author: productData.author,
        category: (m.category || {}).name || m.category,
        likes: productData.likes,
        downloads: productData.downloads,
        makes: productData.makes,
        printTime: m.printTime,
        filament: m.filamentUsed || m.filament
      }, null, 2);
    } else {
      const slug = origUrl.split('/models/')[1]?.split('?')[0] || '';
      productCtx = 'SOURCE URL: ' + origUrl + '\nPLATFORM: MakerWorld\nMODEL SLUG: ' + slug + '\n(No numeric ID in URL — Claude will infer from slug and user inputs)';
      productData = { sourceHost: 'makerworld.com' };
    }

  // ── Printables: use GraphQL API ──────────────────────────────────
  } else if (origUrl.includes('printables.com')) {
    const idMatch = origUrl.match(/\/model\/(\d+)/);
    if (idMatch) {
      const resp = await $helpers.httpRequest({
        method: 'POST',
        url: 'https://api.printables.com/graphql/',
        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
        body: { query: '{ print(id: ' + idMatch[1] + ') { name description likesCount downloadCount makesCount user { publicUsername } category { name } } }' }
      });
      const m = (resp.data || {}).print || {};
      productData = {
        title: m.name || null,
        description: String(m.description || '').substring(0, 200),
        author: (m.user || {}).publicUsername || null,
        likes: m.likesCount || m.likeCount || null,
        downloads: m.downloadCount || null,
        makes: m.makesCount || m.makeCount || null,
        image: null,
        sourceHost: 'printables.com'
      };
      productCtx = 'SOURCE URL: ' + origUrl + '\n\nSTRUCTURED DATA FROM PRINTABLES API:\n' + JSON.stringify({
        title: productData.title,
        description: String(m.description || '').substring(0, 400),
        author: productData.author,
        category: (m.category || {}).name,
        likes: productData.likes,
        downloads: productData.downloads,
        makes: productData.makes
      }, null, 2);
    } else {
      const slug = origUrl.split('/model/')[1]?.split('?')[0] || '';
      productCtx = 'SOURCE URL: ' + origUrl + '\nPLATFORM: Printables\nMODEL SLUG: ' + slug + '\n(No numeric ID in URL — Claude will infer from slug)';
      productData = { sourceHost: 'printables.com' };
    }

  // ── Generic: attempt HTML scrape ─────────────────────────────────
  } else {
    const html = await $helpers.httpRequest({
      method: 'GET',
      url: origUrl,
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0 Safari/537.36',
        'Accept': 'text/html'
      }
    });
    const raw = typeof html === 'string' ? html : JSON.stringify(html);
    if (raw.length > 200) {
      const text = raw
        .replace(/<script[\s\S]*?<\/script>/gi, ' ')
        .replace(/<style[\s\S]*?<\/style>/gi, ' ')
        .replace(/<[^>]+>/g, ' ')
        .replace(/\s{2,}/g, ' ').trim().substring(0, 4000);
      productCtx = 'SOURCE URL: ' + origUrl + '\n\nSCRAPED TEXT:\n' + text;
    } else {
      productCtx = 'SOURCE URL: ' + origUrl + '\n(Scrape returned minimal content)';
    }
    productData = { sourceHost: origUrl.replace(/^https?:\/\//, '').split('/')[0] };
  }

} catch (e) {
  productCtx = 'SOURCE URL: ' + origUrl + '\n(Fetch error: ' + String(e.message || e).substring(0, 200) + ' — Claude will infer from URL and user inputs)';
}

return [{ json: { productContext: productCtx, product: productData } }];

const body = $json.body;

if (body.productContext) {
  return [{ json: { productContext: body.productContext, originalRequest: body } }];
}

if (body.description) {
  return [{ json: { productContext: 'PRODUCT IDEA (free text): "' + body.description + '"', originalRequest: body } }];
}

return [{ json: { productContext: '', originalRequest: body } }];

