const ctx = $input.item.json;
const req = ctx.originalRequest;

const sellFrom      = req.sellFrom      || 'not specified';
const sellTo        = req.sellTo        || 'WORLDWIDE';
const flags         = Array.isArray(req.legalFlags)     ? req.legalFlags.join(', ')     : 'none';
const activeMarkets = Array.isArray(req.activeMarkets)  ? req.activeMarkets.join(', ')  : 'not specified';
const socialMedia   = Array.isArray(req.socialMedia)    ? req.socialMedia.join(', ')    : 'none';
const urlField      = req.url ? JSON.stringify(req.url) : 'null';

const prompt = `You are a 3D printing market analyst specialising in Etsy sales. Analyse this product for commercial viability and return ONLY a single valid JSON object - no markdown, no code fences, no explanation.

${ctx.productContext}

USER INPUTS:
- Category: ${req.category || 'not specified'}
- Target marketplace: ${req.marketplace || 'etsy'}
- Price range hint: ${req.priceRange || 'not specified'}
- Print time: ${req.printTime || 'not specified'}
- Material: ${req.material || 'not specified'}
- Extra costs: ${req.extraCosts || 'none'}
- Experience level: ${req.experience || 'not specified'}
- Active selling markets: ${activeMarkets}
- Social media channels: ${socialMedia}
- Selling from: ${sellFrom}
- Selling to: ${sellTo}
- Legal flags: ${flags}

Return this exact JSON structure with all fields filled in:

{
  "score": <integer 0-100>,
  "verdict": "<punchy one-liner, 3-7 words>",
  "product": {
    "title": "<product title>",
    "author": "<creator name or null>",
    "description": "<2-3 sentences, vivid and specific>",
    "printTime": "<like '3h 20m'>",
    "material": "<like '38g PLA'>",
    "sourceHost": "<domain/... or null>",
    "url": ${urlField},
    "image": null,
    "tags": ["<tag1>","<tag2>","<tag3>"],
    "likes": <integer or null>,
    "saves": <integer or null>,
    "downloads": "<formatted like '8.4k' or null>",
    "prints": "<formatted like '2.1k' or null>",
    "note": "<one bold demand-proof sentence, HTML <b> tags allowed>"
  },
  "market": {
    "searchVolume": <monthly searches integer>,
    "searchTrend": "<like '\u2191 31% YoY' or '\u2192 Stable'>",
    "etsyListings": <integer>,
    "etsyAvgPrice": "<like '\u20ac21'>",
    "topSellerSales": <top seller estimated annual unit sales>,
    "printTime": "<avg print time like '~2.5 hrs'>",
    "unitsPerDay": "<throughput like '\u22482 units/day'>",
    "insight": "<one actionable sentence, <b> tags allowed>"
  },
  "revenue": {
    "unitsPerMonth": <realistic for a new seller - see calibration>,
    "grossRevenue": <unitsPerMonth x sellPrice rounded>,
    "printCost": <total monthly material+energy cost>,
    "etsyFees": <grossRevenue x 0.12 rounded>,
    "netProfit": <grossRevenue - printCost - etsyFees>,
    "sellPrice": "<optimal price like '\u20ac22.40'>"
  },
  "copyright": {
    "etsyBanRisk": "<low|medium|high>",
    "etsyBanReason": "<one sentence>",
    "legalRisk": "<low|medium|high>",
    "legalDesc": "<one sentence, consider seller in ${sellFrom} selling to ${sellTo}>",
    "copyrightRisk": "<low|medium|high>",
    "copyrightDesc": "<one sentence IP check>",
    "insight": "<one-line summary, <b> tags allowed>"
  }
}

── SCORING (0-100) ───────────────────────────────────────────────
Demand/competition ratio 40% + profit margin 35% + legal safety 25%.
80-100 = clear opportunity. 60-79 = viable with effort. 40-59 = marginal. 0-39 = avoid.
Deduct 15-30 points for any IP/copyright risk.

── REVENUE CALIBRATION ──────────────────────────────────────────
unitsPerMonth baseline for a new Etsy seller:
  very low competition (<500 listings, >10k searches) = 45-70
  low competition (500-2k listings) = 25-45
  moderate competition (2k-8k listings) = 15-30
  saturated (>8k listings) = 8-20

sellPrice sweet spot by type:
  Generic functional (hooks, organisers, mounts) = \u20ac10-20
  Decorative / home decor = \u20ac14-28
  Custom / personalised = \u20ac18-40
  Miniatures & gaming = \u20ac12-30
  Premium / large format = \u20ac35-80
  Use the priceRange hint if provided.

printCost = (weight_g x \u20ac0.025) + (print_hours x \u20ac0.05) + 20% overhead, x unitsPerMonth
Check: netProfit = grossRevenue - printCost - etsyFees

── IP / COPYRIGHT ────────────────────────────────────────────────
High risk: Disney/Marvel/DC, Pokemon, Nintendo (Mario/Zelda/etc), sports logos, band logos, any identifiable branded character or logo.
Medium risk: generic fandom designs, historical figures, inspired-by styles.
Low risk: geometric, nature, abstract, original functional items, generic home decor.`;

return [{
  json: {
    claudeRequest: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 2048,
      messages: [{ role: 'user', content: prompt }]
    })
  }
}];

const resp = $input.item.json;

if (resp.error || resp.type === 'error') {
  throw new Error('Anthropic API error: ' + JSON.stringify(resp.error || resp));
}

const content = resp.content;
if (!content || !content[0] || !content[0].text) {
  throw new Error('Unexpected Anthropic response: ' + JSON.stringify(resp));
}

let text = content[0].text.trim();

const fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
if (fenceMatch) text = fenceMatch[1].trim();

const start = text.indexOf('{');
const end   = text.lastIndexOf('}');
if (start === -1 || end <= start) {
  throw new Error('No valid JSON found in Claude response: ' + text.substring(0, 300));
}
text = text.slice(start, end + 1);

let result;
try {
  result = JSON.parse(text);
} catch (e) {
  throw new Error('JSON parse failed: ' + e.message + '\nRaw: ' + text.substring(0, 500));
}

return [{ json: result }];
